/*
 * Generator for src/exr_b44_tables.inc — the two half-indexed perceptual tables
 * used by the B44/B44A codec. Run once on a hosted machine to regenerate:
 *
 *     cc -O2 tools/gen_b44_tables.c -lm -o /tmp/gen_b44 && \
 *         /tmp/gen_b44 > src/exr_b44_tables.inc
 *
 * The table math is byte-for-byte the same as the old runtime b44_init_tables()
 * (which matched OpenEXR). Precomputing lets the core drop <math.h> entirely.
 *
 * Copyright (c) 2014-2026 Syoyo Fujita and TinyEXR authors
 * SPDX-License-Identifier: BSD-3-Clause
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>

static float b44_h2f(uint16_t h) {
    union { uint32_t i; float f; } u;
    int s = (h >> 15) & 1, e = (h >> 10) & 0x1f, m = h & 0x3ff;
    if (e == 0) {
        if (m == 0) { u.i = (uint32_t)s << 31; return u.f; }
        {
            float f = (float)m / 1024.0f * (1.0f / 16384.0f);
            return s ? -f : f;
        }
    } else if (e == 31) {
        u.i = ((uint32_t)s << 31) | 0x7f800000u | ((uint32_t)m << 13);
        return u.f;
    }
    u.i = ((uint32_t)s << 31) | ((uint32_t)(e + 112) << 23) | ((uint32_t)m << 13);
    return u.f;
}

static uint16_t b44_f2h(float f) {
    union { uint32_t i; float f; } u;
    int s, e, m;
    u.f = f;
    s = (int)((u.i >> 31) & 1);
    e = (int)((u.i >> 23) & 0xff);
    m = (int)(u.i & 0x7fffff);
    if (e == 0) return (uint16_t)(s << 15);
    if (e == 255) return (uint16_t)((s << 15) | 0x7c00 | (m >> 13));
    if (e < 113) {
        if (e < 103) return (uint16_t)(s << 15);
        m = (m | 0x800000) >> (114 - e);
        return (uint16_t)((s << 15) | (m >> 13));
    }
    if (e > 142) return (uint16_t)((s << 15) | 0x7c00);
    return (uint16_t)((s << 15) | ((e - 112) << 10) | (m >> 13));
}

static void emit(const char *name, const uint16_t *t) {
    int i;
    printf("static const uint16_t %s[65536] = {\n", name);
    for (i = 0; i < 65536; ++i) {
        printf("%u,", t[i]);
        if ((i & 15) == 15) printf("\n");
    }
    printf("};\n");
}

int main(void) {
    static uint16_t expt[65536], logt[65536];
    int i;
    for (i = 0; i < 65536; ++i) {
        uint16_t x = (uint16_t)i;
        if ((x & 0x7c00) == 0x7c00)
            expt[i] = 0;
        else if (x >= 0x558c && x < 0x8000)
            expt[i] = 0x7bff;
        else
            expt[i] = b44_f2h((float)exp((double)b44_h2f(x) / 8.0));
        if ((x & 0x7c00) == 0x7c00) {
            logt[i] = 0;
        } else if (x > 0x8000) {
            logt[i] = 0;
        } else {
            float f = b44_h2f(x);
            if (f <= 0.0f)
                logt[i] = 0;
            else
                logt[i] = b44_f2h((float)(8.0 * log((double)f)));
        }
    }
    printf("/* Generated by tools/gen_b44_tables.c - do not edit. */\n");
    emit("g_b44_exp_table", expt);
    emit("g_b44_log_table", logt);
    return 0;
}
